// ===== panels: collapse drag-resize search persist (Claude-style) =====
(function(){
  const root = document.documentElement;
  const LS = { get(k){ try { return localStorage.getItem(k); } catch(e){ return null; } }, set(k,v){ try { localStorage.setItem(k,v); } catch(e){} } };
  // restore widths + collapse state
  const railW = parseInt(LS.get("drip-rail"), 10), rrw = parseInt(LS.get("drip-rrw"), 10);
  if (railW >= 200 && railW <= 380) root.style.setProperty("--rail", railW + "px");
  if (rrw >= 280 && rrw <= 600) root.style.setProperty("--rrw", rrw + "px");
  if (LS.get("drip-nav-collapsed") === "1") app.classList.add("nav-collapsed");
  if (LS.get("drip-rr-hidden") === "1") app.classList.add("rr-hidden");
  const syncAudit = () => { const b = $("auditToggle"); if (b) b.classList.toggle("off", app.classList.contains("rr-hidden")); };
  syncAudit();
  // left sidebar: expanded (default) ↔ collapsed icons — one Manus-style sidebar
  const setCollapsed = c => { app.classList.toggle("nav-collapsed", c); LS.set("drip-nav-collapsed", c ? "1" : "0"); };
  const toggleNav = () => setCollapsed(!app.classList.contains("nav-collapsed"));
  const navT = $("navToggle"); if (navT) navT.addEventListener("click", toggleNav);
  const navC = $("navCollapse"); if (navC) navC.addEventListener("click", () => setCollapsed(true));
  const side = $("sideToggle"); if (side) side.addEventListener("click", toggleNav);
  const at = $("auditToggle");
  if (at) at.addEventListener("click", () => { LS.set("drip-rr-hidden", app.classList.toggle("rr-hidden") ? "1" : "0"); syncAudit(); });
  // drag-resize through CSS vars — sidebar (from x=0) and audit rail (from right)
  function makeResize(grip, varName, lsKey, min, max, fromRight){
    if (!grip) return; let on = false;
    grip.addEventListener("mousedown", e => { if (!fromRight && app.classList.contains("nav-collapsed")) return; on = true; grip.classList.add("drag"); app.classList.add("resizing"); document.body.style.userSelect = "none"; e.preventDefault(); });
    window.addEventListener("mousemove", e => { if (!on) return; let w = fromRight ? (window.innerWidth - e.clientX) : e.clientX; w = Math.max(min, Math.min(max, w)); root.style.setProperty(varName, w + "px"); });
    window.addEventListener("mouseup", () => { if (!on) return; on = false; grip.classList.remove("drag"); app.classList.remove("resizing"); document.body.style.userSelect = ""; const cur = parseInt(getComputedStyle(root).getPropertyValue(varName), 10); if (cur) LS.set(lsKey, cur); });
  }
  makeResize($("railGrip"), "--rail", "drip-rail", 200, 380, false);
  makeResize($("rrGrip"), "--rrw", "drip-rrw", 280, 600, true);
  // chat search + collapsible date groups (hierarchy navigation)
  const scroll = $("clScroll"), search = $("clSearch"), empty = $("clEmpty");
  const groupItems = g => { const a = []; let n = g.nextElementSibling; while (n && !n.classList.contains("cl-grp")){ if (n.classList.contains("cl-item")) a.push(n); n = n.nextElementSibling; } return a; };
  if (scroll) scroll.querySelectorAll(".cl-grp").forEach(g => {
    const items = groupItems(g), gn = g.querySelector(".gn"); if (gn) gn.textContent = items.length;
    g.addEventListener("click", () => { const col = g.classList.toggle("col"); items.forEach(it => it.classList.toggle("gcol", col)); });
  });
  if (search) search.addEventListener("input", () => {
    const q = search.value.trim().toLowerCase();
    if (q) scroll.querySelectorAll(".cl-grp").forEach(g => g.classList.remove("col"));
    scroll.querySelectorAll(".cl-item").forEach(it => { if (q) it.classList.remove("gcol"); it.classList.toggle("hide", !!q && it.textContent.toLowerCase().indexOf(q) === -1); });
    let total = 0;
    scroll.querySelectorAll(".cl-grp").forEach(g => { const vis = groupItems(g).filter(it => !it.classList.contains("hide")); total += vis.length; g.classList.toggle("ghide", !!q && vis.length === 0); });
    if (empty) empty.classList.toggle("on", !!q && total === 0);
  });
})();
// ===== settings modal (Manus-style) =====
(function(){
  const mask = $("setMask"); if (!mask) return;
  const modal = mask.querySelector(".set-modal");
  window.__openSettings = function(pane){ mask.classList.add("open"); if (pane) showPane(pane); const ls = $("setLangSel"); if (ls && !ls.dataset.built) buildLang(ls); syncTheme(); };
  const close = () => mask.classList.remove("open");
  $("setClose").addEventListener("click", close);
  mask.addEventListener("mousedown", e => { if (e.target === mask) close(); });
  document.addEventListener("keydown", e => { if (e.code === "Escape" && mask.classList.contains("open")) close(); });
  function showPane(p){ mask.querySelectorAll(".set-link[data-spane]").forEach(b => b.classList.toggle("on", b.getAttribute("data-spane") === p)); mask.querySelectorAll(".set-pane").forEach(el => el.classList.toggle("on", el.getAttribute("data-spane") === p)); modal.querySelector(".set-main").scrollTop = 0; }
  mask.querySelectorAll(".set-link[data-spane]").forEach(b => b.addEventListener("click", () => showPane(b.getAttribute("data-spane"))));
  // language select mirrors the app
  function buildLang(sel){ sel.dataset.built = "1"; sel.innerHTML = Object.keys(LANGS).map(c => '<option value="' + c + '">' + LANGS[c] + '</option>').join(""); sel.value = curLang; sel.addEventListener("change", () => setLang(sel.value)); }
  // theme: light / dark / auto
  function applyTheme(mode){
    try { localStorage.setItem("drip-theme", mode); } catch(e){}
    let dark = mode === "dark";
    if (mode === "auto") { try { dark = window.matchMedia("(prefers-color-scheme: dark)").matches; } catch(e){ dark = false; } }
    document.documentElement.setAttribute("data-theme", dark ? "dark" : "light");
  }
  function syncTheme(){ let m = "auto"; try { m = localStorage.getItem("drip-theme") || "auto"; } catch(e){} mask.querySelectorAll(".theme-opt").forEach(o => o.classList.toggle("on", o.getAttribute("data-theme-opt") === m)); }
  mask.querySelectorAll(".theme-opt").forEach(o => o.addEventListener("click", () => { applyTheme(o.getAttribute("data-theme-opt")); syncTheme(); }));
  const so = $("setSignOut"); if (so) so.addEventListener("click", () => { close(); const s = $("signOut"); if (s) s.click(); });
})();
